(window.webpackJsonp=window.webpackJsonp||[]).push([[256],{883:function(n,r){n.exports="\x3c!-- \r\ntitle: 10-异步编程\r\nsort: \r\n--\x3e \r\n# 异步IO\r\n\r\n- 同步IO浪费CPU的时间\r\n\r\n  > ```python\r\n  > do_some_code()\r\n  > f = open('/path/to/file', 'r')\r\n  > r = f.read() # <== 线程停在此处等待IO操作结果\r\n  > # IO操作完成后线程才能继续执行:\r\n  > do_some_code(r)\r\n  > ```\r\n  >\r\n  > 假如一个程序需要读取键盘输入，使用同步IO极大浪费cpu资源\r\n\r\n- 异步IO，主线程不断重复‘读取消息-处理消息’这一过程\r\n\r\n  > ```python\r\n  > loop = get_event_loop()\r\n  > while True:\r\n  >     event = loop.get_event()\r\n  >     process_event(event)\r\n  > ```\r\n\r\n## 协程\r\n\r\n```python\r\nimport time\r\n\r\n\r\ndef n1():\r\n    while True:\r\n        print(\"n1 start.\")\r\n        yield\r\n        print(\"n1 sleep start.\")\r\n        time.sleep(1)\r\n        print(\"n1 sleep over\")\r\n\r\n\r\ndef n2():\r\n    while True:\r\n        print(\"n2 start.\")\r\n        yield\r\n        print(\"n2 sleep start.\")\r\n        time.sleep(0.5)\r\n        print(\"n2 sleep over\")\r\n\r\n\r\nn1 = n1()\r\nn2 = n2()\r\nwhile True:\r\n    next(n1)\r\n    next(n2)\r\n```\r\n\r\n> 子程序调用总是一个入口，一次返回，调用顺序明确。\r\n>\r\n> 而协程的调用和子程序不同。\r\n>\r\n> 执行过程中，在子程序内部可中断，然后转而执行别的子程序，在适当的时候再返回来接着执行。\r\n>\r\n> 例子：\r\n>\r\n> ```python\r\n> def A():\r\n>     print('1')\r\n>     print('2')\r\n>     print('3')\r\n> \r\n> def B():\r\n>     print('x')\r\n>     print('y')\r\n>     print('z')\r\n> '''\r\n> 由协程执行\r\n> 1\r\n> 2\r\n> x\r\n> y\r\n> 3\r\n> z\r\n> '''\r\n> ```\r\n>\r\n> 看似多进程，但却是一个进程。\r\n>\r\n> Python对协程的支持是通过generator实现的。\r\n>\r\n> 传统是一个线程写消息，一个线程取消息，但一不小心就可能死锁。\r\n>\r\n> 改用协程，生产消息后，直接通过`yield`跳转到执行，待执行完毕后，切换继续生产，效率极高\r\n\r\n- 例子\r\n\r\n  ```python\r\n  def consumer():\r\n      r = ''\r\n      while True:\r\n          # 接收send的值, 并将r返回至 produce,\r\n          n = yield r  \r\n          # 下次send从这里开始执行\r\n          if not n:\r\n              return\r\n          print('[CONSUMER] Consuming %s...' % n)\r\n          r = '200 OK'\r\n  \r\n  c = consumer()\r\n  \r\n  def produce(c):\r\n      # 作用类似于next(c),r为空，n为None。\r\n      c.send(None)    # 启动生成器, yield r 为空\r\n      n = 0\r\n      while n < 5:\r\n          n = n + 1\r\n          print('[PRODUCER] Producing %s...' % n)\r\n          # 传入值n=1，n被赋值为1\r\n          # 进入第二次循环 yield r,将 r yield至 consumer。\r\n          r = c.send(n)\r\n          print('[PRODUCER] Consumer return: %s' % r)\r\n      c.close()\r\n  \r\n  \r\n  c = consumer()\r\n  produce(c)\r\n  \r\n  ```\r\n\r\n- 运行结果\r\n\r\n  ```python\r\n  [PRODUCER] Producing 1...\r\n  [CONSUMER] Consuming 1...\r\n  [PRODUCER] Consumer return: 200 OK\r\n  [PRODUCER] Producing 2...\r\n  [CONSUMER] Consuming 2...\r\n  [PRODUCER] Consumer return: 200 OK\r\n  [PRODUCER] Producing 3...\r\n  [CONSUMER] Consuming 3...\r\n  [PRODUCER] Consumer return: 200 OK\r\n  [PRODUCER] Producing 4...\r\n  [CONSUMER] Consuming 4...\r\n  [PRODUCER] Consumer return: 200 OK\r\n  [PRODUCER] Producing 5...\r\n  [CONSUMER] Consuming 5...\r\n  [PRODUCER] Consumer return: 200 OK\r\n  ```\r\n\r\n\r\n## asyncio\r\n\r\n> `asyncio`是python标准库，内置异步IO的支持。\r\n>\r\n> 即一个消息循环，从模块中直接获取一个`EventLoop`的引用，\r\n>\r\n> 然后把协程扔到`EventLoop`中执行。\r\n\r\n- `yield from`\r\n\r\n  ```python\r\n  # 等价于\r\n  titles = ['Python','Java','C++']\r\n  for title in titles:　# 等价于yield from titles\r\n      yield title　\r\n  ```\r\n\r\n- Hello Async\r\n\r\n  ```python\r\n  import asyncio\r\n  \r\n  @asyncio.coroutine\r\n  def hello():\r\n      print(\"Hello async!\")\r\n      # 异步调用asyncio.sleep(1):\r\n      r = yield from asyncio.sleep(1)\r\n      # yield语法用于调用另一个generator\r\n      print(\"Hello again!\")\r\n  \r\n  # 获取EventLoop:\r\n  loop = asyncio.get_event_loop()\r\n  # 执行coroutine\r\n  loop.run_until_complete(hello())\r\n  loop.close()\r\n  ```\r\n\r\n- `yield from`\r\n\r\n  > yield from titles\r\n  >\r\n  > 相当于 for title in titles\r\n\r\n- 例子\r\n\r\n  ```python\r\n  def generator_1():\r\n      total = 0\r\n      while True:\r\n          x = yield \r\n          print('加',x)\r\n          if not x:\r\n              break\r\n          total += x\r\n      return total\r\n  def generator_2(): # 委托生成器\r\n      while True:\r\n          total = yield from generator_1() # 子生成器\r\n          print('加和总数是:',total)\r\n  def main(): # 调用方\r\n      g1 = generator_1()\r\n      g1.send(None)\r\n      g1.send(2)\r\n      g1.send(3)\r\n      g1.send(None)\r\n      # g2 = generator_2()\r\n      # g2.send(None)\r\n      # g2.send(2)\r\n      # g2.send(3)\r\n      # g2.send(None)\r\n      \r\n  main()\r\n  ```\r\n\r\n  > 【子生成器】：yield from后的generator_1()生成器函数是**子生成器**\r\n  > 【委托生成器】：generator_2()是程序中的**委托生成器**，它负责委托**子生成器**完成具体任务。\r\n  > 【调用方】：main()是程序中的**调用方**，负责调用委托生成器。\r\n\r\n- 显示当前线程\r\n\r\n  ```python\r\n  import threading\r\n  import asyncio\r\n  \r\n  @asyncio.coroutine\r\n  def hello():\r\n      print('Hello world! (%s)' % threading.currentThread())\r\n      yield from asyncio.sleep(1)\r\n      print('Hello again! (%s)' % threading.currentThread())\r\n  \r\n  loop = asyncio.get_event_loop()\r\n  tasks = [hello(), hello()]\r\n  loop.run_until_complete(asyncio.wait(tasks))\r\n  loop.close()\r\n  '''\r\n  Hello world! (<_MainThread(MainThread, started 13716)>)\r\n  Hello world! (<_MainThread(MainThread, started 13716)>)\r\n  Hello again! (<_MainThread(MainThread, started 13716)>)\r\n  Hello again! (<_MainThread(MainThread, started 13716)>)\r\n  '''\r\n  ```\r\n\r\n- 例子\r\n\r\n  ```python\r\n  # 使用同步方式编写异步功能\r\n  import time\r\n  import asyncio\r\n  @asyncio.coroutine # 标志协程的装饰器\r\n  def taskIO_1():\r\n      print('开始运行IO任务1...')\r\n      yield from asyncio.sleep(2)  # 假设该任务耗时2s\r\n      print('IO任务1已完成，耗时2s')\r\n      return taskIO_1.__name__\r\n  @asyncio.coroutine # 标志协程的装饰器\r\n  def taskIO_2():\r\n      print('开始运行IO任务2...')\r\n      yield from asyncio.sleep(3)  # 假设该任务耗时3s\r\n      print('IO任务2已完成，耗时3s')\r\n      return taskIO_2.__name__\r\n  @asyncio.coroutine # 标志协程的装饰器\r\n  def main(): # 调用方\r\n      tasks = [taskIO_1(), taskIO_2()]  # 把所有任务添加到task中\r\n      done,pending = yield from asyncio.wait(tasks) # 子生成器\r\n      for r in done: # done和pending都是一个任务，所以返回结果需要逐个调用result()\r\n          print('协程无序返回值：'+r.result())\r\n\r\n  if __name__ == '__main__':\r\n      start = time.time()\r\n      loop = asyncio.get_event_loop() # 创建一个事件循环对象loop\r\n      try:\r\n          loop.run_until_complete(main()) # 完成事件循环，直到最后一个任务结束\r\n      finally:\r\n          loop.close() # 结束事件循环\r\n      print('所有IO任务总耗时%.5f秒' % float(time.time()-start))\r\n  ```\r\n  \r\n  > done表示已完成的任务列表，pending表示未完成的任务列表。\r\n  >\r\n  > **遇到**该**任务中的`yield from`中断**，开始**处理下一个事件**\r\n  >\r\n  > 当`yield from`后面的子生成器**完成任务**时，该事件才再次**被唤醒**\r\n  \r\n- 使用`async`\r\n\r\n  ```python\r\n  import time\r\n  import asyncio\r\n  async def taskIO_1():\r\n      print('开始运行IO任务1...')\r\n      await asyncio.sleep(2)  # 假设该任务耗时2s\r\n      print('IO任务1已完成，耗时2s')\r\n      return taskIO_1.__name__\r\n  async def taskIO_2():\r\n      print('开始运行IO任务2...')\r\n      await asyncio.sleep(3)  # 假设该任务耗时3s\r\n      print('IO任务2已完成，耗时3s')\r\n      return taskIO_2.__name__\r\n  async def main(): # 调用方\r\n      tasks = [taskIO_1(), taskIO_2()]  # 把所有任务添加到task中\r\n      done,pending = await asyncio.wait(tasks) # 子生成器\r\n      for r in done: # done和pending都是一个任务，所以返回结果需要逐个调用result()\r\n          print('协程无序返回值：'+r.result())\r\n  \r\n  if __name__ == '__main__':\r\n      start = time.time()\r\n      loop = asyncio.get_event_loop() # 创建一个事件循环对象loop\r\n      try:\r\n          loop.run_until_complete(main()) # 完成事件循环，直到最后一个任务结束\r\n      finally:\r\n          loop.close() # 结束事件循环\r\n      print('所有IO任务总耗时%.5f秒' % float(time.time()-start))\r\n  \r\n  ```\r\n\r\n  \r\n\r\n### 使用异步连接网络\r\n\r\n```python\r\nimport asyncio\r\n\r\n@asyncio.coroutine\r\ndef wget(host):\r\n    print('wget %s...' % host)\r\n    connect = asyncio.open_connection(host, 80)\r\n    reader, writer = yield from connect\r\n    header = 'GET / HTTP/1.0\\r\\nHost: %s\\r\\n\\r\\n' % host\r\n    writer.write(header.encode('utf-8'))\r\n    yield from writer.drain()\r\n    while True:\r\n        line = yield from reader.readline()\r\n        if line == b'\\r\\n':\r\n            break\r\n        print('%s header > %s' % (host, line.decode('utf-8').rstrip()))\r\n    # Ignore the body, close the socket\r\n    writer.close()\r\n\r\nloop = asyncio.get_event_loop()\r\ntasks = [wget(host) for host in ['www.sina.com.cn', 'www.sohu.com', 'www.163.com']]\r\nloop.run_until_complete(asyncio.wait(tasks))\r\nloop.close()\r\n```\r\n\r\n## async/await\r\n\r\n> Python 3.5 后引入了新的`async`与`await`\r\n\r\n```python\r\nasync def hello():\r\n    print(\"Hello world!\")\r\n    r = await asyncio.sleep(1)\r\n    print(\"Hello again!\")\r\n```\r\n\r\n## greenlet\r\n\r\n```python\r\nfrom greenlet import greenlet\r\n\r\nfunc1():\r\n    print(\"1 start\")\r\n    g2.switch()\r\n    \r\nfunc2():\r\n    print(\"2 start\")\r\n    g1.switch()\r\n    \r\ng1 = greenlet(func1)\r\ng2 = greenlet(func2)\r\ng1.switch()\r\n```\r\n\r\n"}}]);